{
    "level": "B1",
    "intro": "W tym temacie nauczysz się łączyć wzmacniacze z przymiotnikami i przysłówkami: <strong>very, really, so, too, absolutely, quite, rather, pretty</strong>.",
    "rules": [
        {
            "label": "GRADABLE",
            "color": "emerald",
            "text": "Ze zwykłymi gradable adjectives często używamy <strong>very / really / pretty / quite</strong>.",
            "example": "very cold / really good / quite busy"
        },
        {
            "label": "STRONG",
            "color": "blue",
            "text": "Przy strong adjectives bardziej naturalnie brzmią <strong>absolutely / completely / totally</strong>.",
            "example": "absolutely amazing / completely impossible"
        },
        {
            "label": "TOO",
            "color": "amber",
            "text": "<strong>Too</strong> oznacza „więcej, niż trzeba / niż dobrze”.",
            "example": "too expensive / too late"
        }
    ]
}

{
    "title": "1. Najczęstsze wzmacniacze",
    "intro": "Warto znać nie tylko znaczenie, ale też typowe połączenia.",
    "items": [
        {
            "label": "zwykłe wzmocnienie",
            "title": "very / really / pretty / quite",
            "subtitle": "very busy, really happy, pretty good, quite small"
        },
        {
            "label": "silny przymiotnik",
            "title": "absolutely / completely / totally",
            "subtitle": "absolutely amazing, completely wrong"
        },
        {
            "label": "za dużo",
            "title": "too + adjective",
            "subtitle": "too noisy, too heavy, too late"
        },
        {
            "label": "wystarczająco",
            "title": "adjective + enough",
            "subtitle": "warm enough, fast enough"
        }
    ]
}

{
    "title": "2. Jak wybrać naturalne słowo",
    "sections": [
        {
            "label": "Very, really, so, quite",
            "color": "emerald",
            "description": "Te słowa często stoją przed <strong>gradable adjectives</strong> i przysłówkami.",
            "examples": [
                {
                    "en": "It is very cold today.",
                    "ua": "Dziś jest bardzo zimno."
                },
                {
                    "en": "She is really friendly.",
                    "ua": "Ona jest naprawdę miła."
                },
                {
                    "en": "The room was quite small.",
                    "ua": "Pokój był dość mały."
                }
            ]
        },
        {
            "label": "Absolutely, completely, totally",
            "color": "blue",
            "description": "Te wzmacniacze często lepiej pasują do <strong>strong adjectives</strong>.",
            "examples": [
                {
                    "en": "The view was absolutely amazing.",
                    "ua": "Widok był absolutnie niesamowity."
                },
                {
                    "en": "That answer is completely wrong.",
                    "ua": "Ta odpowiedź jest całkowicie błędna."
                },
                {
                    "en": "I am totally exhausted.",
                    "ua": "Jestem kompletnie wyczerpany."
                }
            ],
            "note": "Wyrażenia typu <em>very amazing</em> są możliwe, ale często brzmią mniej naturalnie."
        },
        {
            "label": "Too i enough",
            "color": "amber",
            "description": "<strong>Too</strong> ma znaczenie negatywne, a <strong>enough</strong> pokazuje wystarczalność.",
            "examples": [
                {
                    "en": "This bag is too heavy.",
                    "ua": "Ta torba jest zbyt ciężka."
                },
                {
                    "en": "The water is warm enough now.",
                    "ua": "Woda jest teraz wystarczająco ciepła."
                },
                {
                    "en": "He is not old enough to drive.",
                    "ua": "Nie jest jeszcze wystarczająco dorosły, żeby prowadzić."
                }
            ],
            "note": "Pamiętaj o szyku: <strong>too + adjective</strong>, ale <strong>adjective + enough</strong>."
        }
    ]
}

{
    "title": "3. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Very przy strong adjective.",
            "wrong": "The film was very amazing.",
            "right": "✅ <span class=\"font-mono\">The film was absolutely amazing.</span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Too zamiast very.",
            "wrong": "The food is too good.",
            "right": "✅ <span class=\"font-mono\">The food is very good.</span> <span class=\"text-slate-500\">(jeśli znaczenie jest pozytywne)</span>"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Złe miejsce enough.",
            "wrong": "The room is enough big.",
            "right": "✅ <span class=\"font-mono\">The room is big enough.</span>"
        }
    ]
}

{
    "title": "4. Krótkie podsumowanie",
    "items": [
        "<strong>Very / really / quite / pretty</strong> często łączą się ze zwykłymi gradable adjectives.",
        "<strong>Absolutely / completely / totally</strong> często pasują do strong adjectives.",
        "<strong>Too</strong> oznacza więcej, niż trzeba, i często ma negatywne znaczenie.",
        "<strong>Enough</strong> stoi po przymiotniku: <em>warm enough</em>.",
        "Wybieraj wzmacniacz nie tylko według siły, ale też według typu przymiotnika."
    ]
}

